SELECT (YEAR(?date) AS ?year) WHERE {
  ?olympics wdt:P31 wd:Q468214;
            wdt:P17 wd:Q30;
            wdt:P179 wd:Q16604;
            wdt:P585 ?date.
}
ORDER BY DESC(?date)
LIMIT 1

SELECT ?year WHERE {
  ?olympics wdt:P31 wd:Q16604 .
  {
    ?olympics wdt:P17 wd:Q30 .
  }
  UNION
  {
    ?olympics wdt:P276 ?city .
    ?city wdt:P17 wd:Q30 .
  }
  ?olympics wdt:P585 ?date .
  BIND(YEAR(?date) AS ?year)
}
ORDER BY DESC(?year)
LIMIT 1

SELECT (YEAR(?date) AS ?year) WHERE {
  ?olympics wdt:P31 wd:Q16604 .
  ?olympics wdt:P585 ?date .
  {
    ?olympics wdt:P17 wd:Q30 .
  }
  UNION
  {
    ?olympics wdt:P276 ?city .
    ?city wdt:P17 wd:Q30 .
  }
}
ORDER BY DESC(?date)
LIMIT 1

SELECT (COUNT(*) AS ?count) WHERE {
  ?event wdt:P31 wd:Q16604 .
  ?event wdt:P17 wd:Q30 .
}

SELECT (COUNT(*) AS ?count) WHERE {
  ?event wdt:P31 wd:Q16604 .
  ?event wdt:P276 ?city .
  ?city wdt:P17 wd:Q30 .
}

SELECT (YEAR(?date) AS ?year) WHERE {
